/**
 * @public
 */
export interface BreakpointProps<T> {
    /** Whether the breakpoint is matched. */
    matches: boolean;
    /** The props that should be applied if the breakpoint is matched. */
    props: T;
}
/**
 * `useBreakpointProps` is a hook that returns an object with all matching props
 * that are passed in. In case of multiple props matching and having the same
 * property, the last matching prop takes precedence.
 * @public
 */
export declare function useBreakpointProps<T>(matchesProps: BreakpointProps<T>[]): T;
